// BTDropdownList barrel — atoms layer.
export 'dropdown_list.types.dart';
export 'dropdown_list.widget.dart';

// BTDropdownList types — Figma source: node 668-8852.
import '../avatar/avatar.types.dart';

/// Visual layout of the dropdown list.
enum BTDropdownListVariant {
  /// Plain text-only rows.
  list,

  /// Avatar circle + name label rows.
  combobox,

  /// Checkbox + label rows. Checked rows receive a brand-primary-subtle bg.
  checkbox,

  /// Radio button + label rows. Selected row receives brand-primary-subtle bg.
  radio,
}

/// A single row item in [BTDropdownList].
///
/// Generic over [T] so callers can use any value type (String, int, enum …).
class BTDropdownItem<T> {
  const BTDropdownItem({
    this.value,
    this.label = '',
    this.disabled = false,
    this.checked = false,
    this.avatar,
    this.removable = false,
  });

  /// Unique identifier emitted on selection.
  /// Optional — rows with a null value are non-interactive (no onSelect fired).
  final T? value;

  /// Display label shown in the row. Defaults to empty string.
  final String label;

  /// When true the row is non-interactive.
  final bool disabled;

  /// Whether this item is checked — used by [BTDropdownListVariant.checkbox]
  /// and [BTDropdownListVariant.radio] to highlight the row and render the
  /// appropriate control in the selected state.
  final bool checked;

  /// Avatar payload — only rendered in the [BTDropdownListVariant.combobox]
  /// variant. Delegates all rendering to [BTAvatar] (xs = 24 px).
  final BTAvatarItem? avatar;

  /// When true, renders a × (cancel) icon on the right side of the row using
  /// space-between layout. Signals that tapping the row performs a destructive
  /// action (e.g. removing this filter). Used by BTDataTable's filter-overflow
  /// dropdown to make the remove affordance clear to users.
  final bool removable;
}

/// BTDropdownList — floating option list atom.
/// Figma source: node 668-8852.
///
/// Purely presentational. Caller handles positioning, filtering, and
/// toggling visibility. When [items] is empty the "not found" illustration
/// is shown automatically.
///
/// ## Usage:
/// ```dart
/// // List variant
/// BTDropdownList<String>(
///   items: const [
///     BTDropdownItem(value: 'a', label: 'Option A'),
///     BTDropdownItem(value: 'b', label: 'Option B'),
///   ],
///   onSelect: (value) => debugPrint('selected: $value'),
/// )
///
/// // Combobox with search
/// BTDropdownList<String>(
///   variant: BTDropdownListVariant.combobox,
///   hasSearch: true,
///   searchQuery: _query,
///   onSearch: (q) => setState(() => _query = q),
///   items: _filteredUsers,
///   onSelect: _handleSelectUser,
/// )
///
/// // Checkbox multi-select
/// BTDropdownList<String>(
///   variant: BTDropdownListVariant.checkbox,
///   items: _items.map((i) => BTDropdownItem(
///     value: i.value,
///     label: i.label,
///     checked: _selected.contains(i.value),
///   )).toList(),
///   onSelect: (value) => setState(() {
///     _selected.contains(value)
///       ? _selected.remove(value)
///       : _selected.add(value);
///   }),
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../checkbox/checkbox.widget.dart';
import 'package:btech_ui/src/components/atoms/dropdown_list/dropdown_list.types.dart';
import '../radio-button/radio_button.widget.dart';
import '../scrollbar/scrollbar.widget.dart';
import '../avatar/avatar.types.dart';
import '../avatar/avatar.widget.dart';
import '../input-search/input_search.widget.dart';
import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';

/// Floating option list. See file header for usage examples.
class BTDropdownList<T> extends StatefulWidget {
  const BTDropdownList({
    required this.items,
    this.variant = BTDropdownListVariant.list,
    this.hasSearch = false,
    this.searchQuery = '',
    this.onSearch,
    this.onSearchSubmit,
    this.onSelect,
    this.emptyLabel = 'No result found.',
    this.width = 210.0,
    super.key,
  });

  /// Visual layout variant.
  final BTDropdownListVariant variant;

  /// Items to display. Empty list triggers the empty-state illustration.
  final List<BTDropdownItem<T>> items;

  /// Show a search input at the top.
  final bool hasSearch;

  /// Current search query value (controlled).
  final String searchQuery;

  /// Called when the user types in the search box.
  final ValueChanged<String>? onSearch;

  /// Called when the user submits the search input (presses Enter / search key).
  final ValueChanged<String>? onSearchSubmit;

  /// Called when the user taps a non-disabled item.
  final ValueChanged<T>? onSelect;

  /// Text shown beneath the empty-state illustration.
  final String emptyLabel;

  /// Width of the dropdown panel. Defaults to 210.
  ///
  /// When `null`, the panel sizes to its content width (via [IntrinsicWidth]),
  /// honouring any incoming min/max width constraints from the parent. The
  /// [BTDropdown] molecule uses this so the floating list can be wider or
  /// narrower than its trigger and respond to `align`.
  final double? width;

  @override
  State<BTDropdownList<T>> createState() => _BTDropdownListState<T>();
}

class _BTDropdownListState<T> extends State<BTDropdownList<T>> {
  final _scrollController = ScrollController();

  @override
  void dispose() {
    _scrollController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;

    final panel = Container(
      width: widget.width,
      constraints: BoxConstraints(maxHeight: 240.0),
      decoration: BoxDecoration(
        color: colors.bg.primary,
        border: Border.all(color: colors.border.primary, width: 1),
        borderRadius: BorderRadius.circular(context.btRadius.sm),
        boxShadow: const [
          // elevation/md — matches var(--shadow-elevation-md)
          BoxShadow(
            color: Color(0x0F000000),
            blurRadius: 4,
            spreadRadius: -2,
            offset: Offset(0, 2),
          ),
          BoxShadow(
            color: Color(0x1A000000),
            blurRadius: 6,
            spreadRadius: -1,
            offset: Offset(0, 4),
          ),
        ],
      ),
      clipBehavior: Clip.antiAlias,
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Search bar (sticky — always visible) ─────────────────────
          if (widget.hasSearch)
            Padding(
              padding: EdgeInsets.symmetric(horizontal: 12.0, vertical: 8.0),
              child: BTInputSearch(
                value: widget.searchQuery,
                onChanged: widget.onSearch,
                onSearch: widget.onSearchSubmit,
              ),
            ),

          // ── Items or empty state (scrollable) ────────────────────────
          Flexible(
            child: BTScrollbar(
              controller: _scrollController,
              child: SingleChildScrollView(
                controller: _scrollController,
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    if (widget.items.isEmpty)
                      _EmptyState(label: widget.emptyLabel, colors: colors)
                    else
                      ...widget.items.map(
                        (item) => _ListItem<T>(
                          item: item,
                          variant: widget.variant,
                          colors: colors,
                          onTap: item.disabled || item.value == null
                              ? null
                              : () => widget.onSelect?.call(item.value as T),
                        ),
                      ),
                  ],
                ),
              ),
            ),
          ),
        ],
      ),
    );

    // Width null → size to content. IntrinsicWidth makes the stretched Column
    // children share the content width instead of expanding to the (unbounded)
    // incoming constraints. A fixed width skips this for zero overhead.
    return widget.width == null ? IntrinsicWidth(child: panel) : panel;
  }
}

// ── List item ───────────────────────────────────────────────────────────────

class _ListItem<T> extends StatefulWidget {
  const _ListItem({
    required this.item,
    required this.variant,
    required this.colors,
    this.onTap,
  });

  final BTDropdownItem<T> item;
  final BTDropdownListVariant variant;
  final BTColorTheme colors;
  final VoidCallback? onTap;

  @override
  State<_ListItem<T>> createState() => _ListItemState<T>();
}

class _ListItemState<T> extends State<_ListItem<T>> {
  bool _isHovered = false;
  bool _isPressed = false;

  // Checked background takes priority; hover/press layered on top.
  // Mirrors the web CSS rules:
  //   checked               → background: var(--color-brand-primary-subtle)
  //   :hover (not checked)  → background: var(--bg-subtle)
  //   :active (not checked) → background: var(--bg-secondary)
  Color get _bgColor {
    if (widget.item.disabled) return Colors.transparent;
    if (widget.item.checked) return widget.colors.brand.primarySubtle;
    if (_isPressed) return widget.colors.bg.secondary;
    if (_isHovered) return widget.colors.bg.subtle;
    return Colors.transparent;
  }

  @override
  Widget build(BuildContext context) {
    final isCombobox = widget.variant == BTDropdownListVariant.combobox;
    final isCheckbox = widget.variant == BTDropdownListVariant.checkbox;
    final isRadio = widget.variant == BTDropdownListVariant.radio;

    return Opacity(
      opacity: widget.item.disabled ? 0.4 : 1.0,
      child: MouseRegion(
        cursor: widget.item.disabled
            ? SystemMouseCursors.forbidden
            : SystemMouseCursors.click,
        onEnter: widget.item.disabled
            ? null
            : (_) => setState(() => _isHovered = true),
        onExit: widget.item.disabled
            ? null
            : (_) => setState(() => _isHovered = false),
        child: GestureDetector(
          onTap: widget.item.disabled ? null : widget.onTap,
          onTapDown: widget.item.disabled
              ? null
              : (_) => setState(() => _isPressed = true),
          onTapUp: widget.item.disabled
              ? null
              : (_) => setState(() => _isPressed = false),
          onTapCancel: widget.item.disabled
              ? null
              : () => setState(() => _isPressed = false),
          // Plain Container — setState drives the repaint instantly.
          // AnimatedContainer causes a "blip" on quick taps (CLAUDE.md §12).
          child: Container(
            padding: EdgeInsets.symmetric(horizontal: 8.0, vertical: 8.0),
            color: _bgColor,
            child: Row(
              children: [
                // ── Checkbox control ──────────────────────────────────
                if (isCheckbox) ...[
                  IgnorePointer(
                    child: BTCheckbox(
                      checked: widget.item.checked,
                      disabled: widget.item.disabled,
                      onChanged: null,
                    ),
                  ),
                  SizedBox(width: 8.0),
                ],

                // ── Radio control ─────────────────────────────────────
                if (isRadio) ...[
                  IgnorePointer(
                    child: BTRadioButton<bool>(
                      groupValue: widget.item.checked,
                      value: true,
                      onChanged: (_) {},
                      disabled: widget.item.disabled,
                    ),
                  ),
                  SizedBox(width: 8.0),
                ],

                // ── Avatar (combobox only) ─────────────────────────────
                if (isCombobox && widget.item.avatar != null) ...[
                  BTAvatar(
                    item: widget.item.avatar,
                    size: BTAvatarSize.xs,
                  ),
                  SizedBox(width: 8.0),
                ],

                // ── Label ─────────────────────────────────────────────
                Expanded(
                  child: Text(
                    widget.item.label,
                    style: TextStyle(
                      fontSize: 14.0,
                      fontWeight: FontWeight.w500,
                      color: widget.colors.text.primary,
                      fontFamily: BTTypography.fontFamily,
                      height: 16 / 14,
                    ),
                    overflow: TextOverflow.ellipsis,
                    maxLines: 1,
                  ),
                ),

                // ── Remove (×) affordance — space-between with label ──
                if (widget.item.removable) ...[
                  const SizedBox(width: 8.0),
                  Icon(
                    Icons.cancel,
                    size: 16,
                    color: widget.colors.icon.secondary,
                  ),
                ],
              ],
            ),
          ),
        ),
      ),
    );
  }
}

// ── Empty state ─────────────────────────────────────────────────────────────

class _EmptyState extends StatelessWidget {
  const _EmptyState({required this.label, required this.colors});

  final String label;
  final BTColorTheme colors;

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.all(24.0),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          SvgPicture.asset(
            'packages/btech_assets/assets/illus/dropdown_empty_state.svg',
            width: 80.0,
          ),
          SizedBox(height: 4.0),
          Text(
            label,
            style: TextStyle(
              fontSize: 11.0,
              fontWeight: FontWeight.w500,
              color: Color(0xFF7E93A8), // component-specific — hardcoded per CLAUDE.md §2
              height: 16 / 11,
            ),
            textAlign: TextAlign.center,
          ),
        ],
      ),
    );
  }
}
